import React, { Component } from 'react';
import * as algoliasearch from 'algoliasearch';
import { InstantSearch, SearchBox, Hits, connectHits, connectInfiniteHits, InfiniteHits } from 'react-instantsearch-dom';
import { GoogleMapsLoader, GeoSearch, Marker, Control } from 'react-instantsearch-dom-maps';


import './App.css';
const searchClient = algoliasearch('43H3UXBYSV', '773c0bceb7c1762989f544586f92f65f');
let index = searchClient.initIndex("Housing");

function infiniteHits({ hits, refine }){
    return(
    <div className="hits housing">
        {hits.map(hit => (
            <div key={hit.objectID}>
                {hit.display? <div className="hit" ><h2 className="name">{hit.property_name}</h2><p>Contact phone: <a href={"tel:"+hit.contact_number}>{hit.contact_number}</a></p><p>Contact email: <a href={"mail-to:"+hit.contact_email}>{hit.contact_email}</a></p><p>Address:
                    <br/>
                    <i>{hit.address.linel}, {hit.address.locality}, {hit.address.state}, {hit.address.postal_code}</i>
                </p><p>Pet policy status: {hit.pet_policy}</p><p>Website: <a href={hit.website} target="_blank">{hit.website}</a></p></div>:''}
            </div>
        ))}
    </div>
)};
const CustomInfiniteHits = connectInfiniteHits(infiniteHits);

class Housing extends Component {
    constructor(props){
        super(props);
    }
    render(){
        index.setSettings({
            'searchableAttributes': [
                'property_name',
                'address',
            ]
        });
        return(
            <div className="container">
                <InstantSearch searchClient={searchClient} indexName="Housing">
                    <SearchBox />
                    <div style={{ height: 500 }} className='col'>
                        <GoogleMapsLoader apiKey="AIzaSyBah20fW-PaxEEUXf7CrZGPp95PusGIL4A">
                            {google => (
                                <GeoSearch
                                    google={google}
                                    initialZoom={8}
                                >
                                    {({ hits }) => (
                                        <div>
                                            {hits.map(hit => hit.display? <Marker key={hit.objectID} hit={hit} onClick={({ event }) => {
                                                document.querySelector(".tooltip").innerHTML = `
                                                    <h4>${hit.property_name}</h4>
                                                     <p>${hit.address.linel}, ${hit.address.locality}, ${hit.address.state}, ${hit.address.postal_code}</p>
                                                `;
                                                document.querySelector(".tooltip").style.top = event.wa.pageY - 120 + 'px';
                                                document.querySelector(".tooltip").style.left = event.wa.pageX - 120 + 'px';
                                            }} /> : '')}
                                            <div className="tooltip"></div>
                                        </div>
                                    )}
                                </GeoSearch>
                            )}
                        </GoogleMapsLoader>
                    </div>
                    <CustomInfiniteHits />
                </InstantSearch>
            </div>
        )}
    }




export default Housing;
